Here's a complete example:

**XAML**
```xml
<RefreshView Command="{Binding RefreshCommand}"
             IsRefreshing="{Binding IsRefreshing}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    SelectionChangedCommand="{Binding SelectionChangedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="*,Auto">
                    <Label Text="{Binding Name}" FontSize="16" />
                    <Label Grid.Column="1" Text="{Binding Status}"
                           TextColor="Gray" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</RefreshView>
```

**ViewModel** (using CommunityToolkit.Mvvm)
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ObservableCollection<Item> Items { get; } = new();

    [RelayCommand]
    private async Task RefreshAsync()
    {
        try
        {
            var data = await _api.GetItemsAsync();
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        }
        finally
        {
            IsRefreshing = false; // stops the spinner
        }
    }

    [RelayCommand]
    private async Task SelectionChangedAsync()
    {
        if (SelectedItem is null) return;

        await _nav.GoToAsync(nameof(DetailPage),
            new Dictionary<string, object> { ["Item"] = SelectedItem });

        SelectedItem = null; // clear so re-selection works
    }
}
```

**Key bindings explained:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `IsRefreshing` | `bool IsRefreshing` | Controls the refresh spinner; set `false` when done |
| `Command` (RefreshView) | `RefreshCommand` | Fires on pull-to-refresh |
| `ItemsSource` | `ObservableCollection<Item>` | Drives the list; auto-updates UI on changes |
| `SelectedItem` | `Item? SelectedItem` | Two-way binding tracks the current selection |
| `SelectionChangedCommand` | `SelectionChangedCommand` | Fires when selection changes; triggers navigation |

**Important details:**
- Set `SelectedItem = null` after navigating so the same row can be tapped again.
- Set `IsRefreshing = false` in a `finally` block so the spinner always stops, even on errors.
- `SelectionMode="Single"` limits selection to one item at a time.
